using Microsoft.AspNetCore.Components;

namespace sv_9c99f26c9aeb48fb9f9e18dc43910e8e;

public enum ThemeMode
{
    Light,
    Dark,
    System
}

/// <summary>
/// Scoped service holding per-circuit theme state.
/// Mutations notify both the Action event (for injected subscribers)
/// and the CascadingValueSource (for [CascadingParameter] subscribers
/// across render-mode boundaries).
/// </summary>
public class ThemeState
{
    private CascadingValueSource<ThemeState>? _source;

    public ThemeMode Mode { get; private set; } = ThemeMode.Light;
    public string AccentColor { get; private set; } = "#0d6efd";

    public event Action? OnChange;

    internal void SetCascadingSource(CascadingValueSource<ThemeState> source)
    {
        _source = source;
    }

    public async Task SetThemeModeAsync(ThemeMode mode)
    {
        if (Mode == mode) return;
        Mode = mode;
        await NotifyAsync();
    }

    public async Task SetAccentColorAsync(string color)
    {
        if (AccentColor == color) return;
        AccentColor = color;
        await NotifyAsync();
    }

    public async Task SetAsync(ThemeMode mode, string accentColor)
    {
        if (Mode == mode && AccentColor == accentColor) return;
        Mode = mode;
        AccentColor = accentColor;
        await NotifyAsync();
    }

    private async Task NotifyAsync()
    {
        OnChange?.Invoke();
        if (_source is not null)
        {
            await _source.NotifyChangedAsync();
        }
    }
}

