@rendermode InteractiveServer
@inject ThemeState Theme
@implements IDisposable

<span class="badge" style="background-color: @Theme.AccentColor;">
    @Theme.Mode
</span>

@code {
    protected override void OnInitialized()
    {
        Theme.OnChange += StateHasChanged;
    }

    public void Dispose()
    {
        Theme.OnChange -= StateHasChanged;
    }
}

@inject ThemeState Theme
@implements IDisposable

<button class="btn btn-sm btn-outline-secondary" @onclick="Toggle">
    @(Theme.Mode switch
    {
        ThemeMode.Light => "☀️ Light",
        ThemeMode.Dark => "🌙 Dark",
        ThemeMode.System => "💻 System",
        _ => "Theme"
    })
</button>

@code {
    protected override void OnInitialized()
    {
        Theme.OnChange += StateHasChanged;
    }

    private async Task Toggle()
    {
        var next = Theme.Mode switch
        {
            ThemeMode.Light => ThemeMode.Dark,
            ThemeMode.Dark => ThemeMode.System,
            ThemeMode.System => ThemeMode.Light,
            _ => ThemeMode.Light
        };
        await Theme.SetThemeModeAsync(next);
    }

    public void Dispose()
    {
        Theme.OnChange -= StateHasChanged;
    }
}

@page "/settings"
@rendermode InteractiveServer
@inject ThemeState Theme
@implements IDisposable

<PageTitle>Settings</PageTitle>

<h1>User Preferences</h1>

<div class="mb-3">
    <label class="form-label">Theme Mode</label>
    <select class="form-select" style="max-width: 200px;"
            value="@Theme.Mode" @onchange="OnModeChanged">
        @foreach (var mode in Enum.GetValues<ThemeMode>())
        {
            <option value="@mode">@mode</option>
        }
    </select>
</div>

<div class="mb-3">
    <label class="form-label">Accent Color</label>
    <input type="color" class="form-control form-control-color"
           value="@Theme.AccentColor" @onchange="OnColorChanged" />
</div>

<div class="mt-4 p-3 border rounded" style="border-color: @Theme.AccentColor !important;">
    <strong>Preview:</strong> Current theme is <em>@Theme.Mode</em>
    with accent <span style="color: @Theme.AccentColor;">@Theme.AccentColor</span>.
</div>

@code {
    protected override void OnInitialized()
    {
        Theme.OnChange += StateHasChanged;
    }

    private async Task OnModeChanged(ChangeEventArgs e)
    {
        if (Enum.TryParse<ThemeMode>(e.Value?.ToString(), out var mode))
        {
            await Theme.SetThemeModeAsync(mode);
        }
    }

    private async Task OnColorChanged(ChangeEventArgs e)
    {
        var color = e.Value?.ToString();
        if (!string.IsNullOrEmpty(color))
        {
            await Theme.SetAccentColorAsync(color);
        }
    }

    public void Dispose()
    {
        Theme.OnChange -= StateHasChanged;
    }
}

